#!/bin/bash
set -e
if echo dGVzdA== | base64 -D >/dev/null 2>&1; then B64FLAG="-D"; else B64FLAG="-d"; fi
mkdir -p pages public/videos
echo 'Writing pages/rooms.js...'
base64 $B64FLAG << 'B64_VID_1' > pages/rooms.js

B64_VID_1
echo 'Video hero applied to Your Room page. Drop rooms-hero.mp4 into public/videos/ to activate it.'
